class User extends Model
{
    use HasFactory, SoftDeletes;

    protected $fillable = ['name', 'email', 'role', 'organization_id'];
    protected $hidden   = ['password', 'remember_token'];
    protected $casts    = ['is_active' => 'boolean', 'settings' => 'array'];

    // Scope: User::active()->role('admin')->get()
    public function scopeActive($query) { return $query->where('is_active', true); }
    public function scopeRole($query, string $role) { return $query->where('role', $role); }

    // Attribute API (Laravel 9+)
    protected function email(): Attribute
    {
        return Attribute::make(set: fn (string $v) => strtolower($v));
    }

    // Relationship
    public function organization(): BelongsTo { return $this->belongsTo(Organization::class); }
}

// app/Models/Concerns/Searchable.php
trait Searchable
{
    public function scopeSearch($query, ?string $term)
    {
        if (empty($term)) return $query;
        $columns = $this->searchable ?? ['name'];
        return $query->where(function ($q) use ($columns, $term) {
            foreach ($columns as $column) {
                $q->orWhere($column, 'ILIKE', "%{$term}%");
            }
        });
    }
}
